import{_ as r,C as h,o as e,c as s,a2 as a,b as n,w as l,a as d,E as i,a3 as u}from"./chunks/framework.Crpw6aS5.js";const g=JSON.parse('{"title":"日本五大综合企业投资","description":"巴菲特2019-2024年持续加仓日本伊藤忠、丸红、三菱、三井、住友","frontmatter":{"title":"日本五大综合企业投资","description":"巴菲特2019-2024年持续加仓日本伊藤忠、丸红、三菱、三井、住友"},"headers":[],"relativePath":"02_concepts/japan-investments.md","filePath":"02_concepts/japan-investments.md"}'),q={name:"02_concepts/japan-investments.md"};function c(p,t,f,m,b,_){const o=h("Mermaid");return e(),s("div",null,[t[1]||(t[1]=a('<h1 id="日本五大综合企业投资" tabindex="-1">日本五大综合企业投资 <a class="header-anchor" href="#日本五大综合企业投资" aria-label="Permalink to &quot;日本五大综合企业投资&quot;">​</a></h1><blockquote><p>&quot;我们简单地看了看他们的财务记录，对其股票的低价感到惊讶。随着岁月流逝，我们对这些公司的钦佩持续增长。&quot; —— <a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，2024年</p></blockquote><p>2019年7月，巴菲特开始买入日本五大综合贸易公司股票。2020-2024年间，他持续加仓，累计成本1.6万亿日元，市值最高达2.9万亿日元。这是伯克希尔有史以来最大规模的非美国投资，也是巴菲特晚年最重要的战略决策之一。</p><hr><h2 id="核心出处" tabindex="-1">核心出处 <a class="header-anchor" href="#核心出处" aria-label="Permalink to &quot;核心出处&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">年份</th><th style="text-align:left;">重点内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><a href="/01_letters/2020年/核心总结.html">核心总结</a></strong></td><td style="text-align:left;">首次披露五大日本公司持仓</td></tr><tr><td style="text-align:left;"><strong><a href="/01_letters/2021年/核心总结.html">核心总结</a></strong></td><td style="text-align:left;">格雷格·阿贝尔访日后增持</td></tr><tr><td style="text-align:left;"><strong><a href="/01_letters/2023年/核心总结.html">核心总结</a></strong></td><td style="text-align:left;">全面增持，五家公司均达约9%</td></tr><tr><td style="text-align:left;"><strong><a href="/01_letters/2024年/核心总结.html">核心总结</a></strong></td><td style="text-align:left;">接近9.9%上限，年股息8.12亿美元</td></tr></tbody></table><hr><h2 id="一、为什么是日本五大综合企业" tabindex="-1">一、为什么是日本五大综合企业 <a class="header-anchor" href="#一、为什么是日本五大综合企业" aria-label="Permalink to &quot;一、为什么是日本五大综合企业&quot;">​</a></h2><p>巴菲特在2023年信中详细解释了投资逻辑：</p><blockquote><p>&quot;<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>继续持有五家非常大的日本公司的被动长期权益，每家公司都以类似于<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>自身运营的高度多元化方式运营。&quot;</p></blockquote><blockquote><p>&quot;五家按字母顺序是：<a href="/search.html?q=伊藤忠">伊藤忠</a>、丸红、三菱、三井和<a href="/search.html?q=住友">住友</a>。每家大型企业又拥有各种业务的权益，许多基于日本，但也有在世界各地运营的业务。&quot;</p></blockquote><blockquote><p>&quot;<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>在2019年7月首次购买了这五家公司的股票。我们简单地看了看他们的财务记录，对其股票的低价感到惊讶。随着岁月流逝，我们对这些公司的钦佩持续增长。&quot;</p></blockquote><p>2024年，巴菲特再次解释：</p><blockquote><p>&quot;这五家公司都在适当时候增加股息，在有意义时回购股票，而且他们的高管薪酬方案远不如美国同行那么激进。&quot;</p></blockquote><hr><h2 id="二、五大公司的共同特点" tabindex="-1">二、五大公司的共同特点 <a class="header-anchor" href="#二、五大公司的共同特点" aria-label="Permalink to &quot;二、五大公司的共同特点&quot;">​</a></h2><p>2023年信中，巴菲特对比了日本五大与美国公司的差异：</p><blockquote><p>&quot;在某些重要方面，所有五家公司——<a href="/search.html?q=伊藤忠">伊藤忠</a>、丸红、三菱、三井和<a href="/search.html?q=住友">住友</a>——都遵循比美国通常实践更为股东友好的政策。&quot;</p></blockquote><blockquote><p>&quot;自从我们开始购买日本股票以来，五家公司都以有吸引力的价格减少了流通股数量。&quot;</p></blockquote><blockquote><p>&quot;同时，所有五家公司管理层的自身薪酬激励远不如美国典型那样激进。&quot;</p></blockquote><blockquote><p>&quot;还要注意，五家公司都只将约三分之一收益作为股息分配——远低于美国公司的平均比例。这意味着，与典型的美国公司相比，这五家公司保留的收益更多，可用于再投资。&quot;</p></blockquote><hr><h2 id="三、持仓规模与回报" tabindex="-1">三、持仓规模与回报 <a class="header-anchor" href="#三、持仓规模与回报" aria-label="Permalink to &quot;三、持仓规模与回报&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">年份</th><th style="text-align:left;">总成本</th><th style="text-align:left;">持股比例</th><th style="text-align:left;">备注</th></tr></thead><tbody><tr><td style="text-align:left;">2019年7月</td><td style="text-align:left;">约6,000亿日元</td><td style="text-align:left;">约5%</td><td style="text-align:left;">首次建仓</td></tr><tr><td style="text-align:left;">2021年</td><td style="text-align:left;">约1.3万亿日元</td><td style="text-align:left;">各约8.8%</td><td style="text-align:left;">格雷格访日后增持</td></tr><tr><td style="text-align:left;">2023年</td><td style="text-align:left;">—</td><td style="text-align:left;">各约9%</td><td style="text-align:left;">全面增持</td></tr><tr><td style="text-align:left;">2024年</td><td style="text-align:left;">1.6万亿日元</td><td style="text-align:left;">各约9%</td><td style="text-align:left;">接近9.9%上限</td></tr></tbody></table><blockquote><p>&quot;我们为五家公司的总成本为1.6万亿日元，年底市值为2.9万亿日元。然而，日元近年来走弱，我们以美元计算的年底未实现收益为61%或80亿美元。&quot; —— 2023年</p></blockquote><hr><h2 id="四、融资策略-日元债券" tabindex="-1">四、融资策略：日元债券 <a class="header-anchor" href="#四、融资策略-日元债券" aria-label="Permalink to &quot;四、融资策略：日元债券&quot;">​</a></h2><p>巴菲特用日元债券为日本投资融资，这是他投资框架的独特体现：</p><blockquote><p>&quot;格雷格和我都不相信我们能够预测主要货币的市场价格。我们也不相信我们能雇用具有这种能力的人。因此，<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>用1.3万亿日元的债券收益为大部分日本仓位融资。这笔债务在日本非常受欢迎，我相信<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>比任何其他美国公司都拥有更多的日元计价债务。&quot;</p></blockquote><p>2024年，巴菲特解释了日元融资的数学：</p><blockquote><p>&quot;我们使用日元融资，因为我们不想要汇率风险敞口。我们借日元买日元资产，这样汇率波动就不会影响我们。现在每年从五家日本公司收到的股息约8.12亿美元，而日元债券的利息成本约1.35亿美元。净收益6.77亿美元，覆盖了债券成本。&quot;</p></blockquote><hr><h2 id="五、与伯克希尔的相似性" tabindex="-1">五、与伯克希尔的相似性 <a class="header-anchor" href="#五、与伯克希尔的相似性" aria-label="Permalink to &quot;五、与伯克希尔的相似性&quot;">​</a></h2><p>巴菲特在2024年信中总结了五家公司与伯克希尔的相似之处：</p><blockquote><p>&quot;这些公司以与<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>自身运营的高度多元化方式成功运营。他们都具有永久持股的心态——就像我们一样。&quot;</p></blockquote><blockquote><p>&quot;我对格雷格及其最终继任者说：他们将在未来几十年持有这个日本头寸，<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔哈撒韦</a>将在未来找到其他与这五家公司富有成效地合作的方式。&quot;</p></blockquote><hr><h2 id="主题关联" tabindex="-1">主题关联 <a class="header-anchor" href="#主题关联" aria-label="Permalink to &quot;主题关联&quot;">​</a></h2>',38)),(e(),n(u,null,{default:l(()=>[i(o,{id:"mermaid-244",class:"mermaid",graph:"graph%20LR%0A%20%20%20%20A%5B%E6%97%A5%E6%9C%AC%E4%BA%94%E5%A4%A7%E6%8A%95%E8%B5%84%5D%20--%3E%20B%5B%E9%95%BF%E6%9C%9F%E4%B8%BB%E4%B9%89%5D%0A%20%20%20%20A%20--%3E%20C%5B%E8%B5%84%E6%9C%AC%E9%85%8D%E7%BD%AE%5D%0A%20%20%20%20A%20--%3E%20D%5B%E5%A4%9A%E5%85%83%E5%8C%96%5D%0A%20%20%20%20A%20--%3E%20E%5B%E7%AE%A1%E7%90%86%E5%B1%82%E9%80%89%E6%8B%A9%5D%0A%20%20%20%20A%20--%3E%20F%5B%E5%86%85%E5%9C%A8%E4%BB%B7%E5%80%BC%5D%0A"})]),fallback:l(()=>[...t[0]||(t[0]=[d(" Loading... ",-1)])]),_:1})),t[2]||(t[2]=a('<hr><h2 id="相关阅读" tabindex="-1">相关阅读 <a class="header-anchor" href="#相关阅读" aria-label="Permalink to &quot;相关阅读&quot;">​</a></h2><ul><li><a href="/search.html?q=多元化">多元化</a> - 为什么投资要适度分散</li><li><a href="/search.html?q=长期主义">长期主义</a> - 什么是真正的长期投资</li><li><a href="/search.html?q=管理层">管理层</a> - 优秀管理层的特征</li></ul><hr><p><em>本页面整理自<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>致股东信原文（2019-2024年），<a href="/search.html?q=慢慢变富的卡尔">慢慢变富的卡尔</a>编辑整理</em></p>',5))])}const k=r(q,[["render",c]]);export{g as __pageData,k as default};
